class Solution:
    def minGroups(self, intervals):
        import heapq
        intervals = sorted(intervals)
        heap = []
        for s, e in intervals:
            if heap and heap[0] < s:
                heapq.heapreplace(heap, e)
            else:
                heapq.heappush(heap, e)
        return len(heap)

