class Solution:
    def minGroups(self, intervals):
        events = []
        for s, e in intervals:
            events.append((s, 1))
            events.append((e + 1, -1))
        events.sort()
        cur = 0
        best = 0
        for _, delta in events:
            cur += delta
            if cur > best:
                best = cur
        return best

